        public static string Inline(string name, string cls = "w-5 h-5")
        {
            if (!_paths.TryGetValue(name?.ToLower() ?? "", out var ps))
                ps = _paths["document"];
            var fill = name is "play" ? "currentColor" : "none";
            var pathsSvg = string.Join("", ps.Select(d =>
                $@"<path stroke-linecap=""round"" stroke-linejoin=""round"" stroke-width=""2"" d=""{d}"" fill=""{fill}""/>"));
            return $@"<svg class=""{cls}"" fill=""none"" stroke=""currentColor"" viewBox=""0 0 24 24"" aria-hidden=""true"">{pathsSvg}</svg>";
        }
        public static string Use(string name, string cls = "w-5 h-5")
            => $@"<svg class=""{cls}"" aria-hidden=""true""><use href=""/images/g-icons.svg#icon-{name}""/></svg>";
        public static IEnumerable<string> AllIconNames => _paths.Keys.OrderBy(k => k);
        public static bool Exists(string name) => _paths.ContainsKey(name?.ToLower() ?? "");
    }
